import{_ as a,o as s,c as t,a0 as i}from"./chunks/framework.B3sz4m_N.js";const p=JSON.parse('{"title":"AI as an Interface Layer","description":"Hows My Commute AI Integration Case Study","frontmatter":{"title":"AI as an Interface Layer","description":"Hows My Commute AI Integration Case Study","pageClass":"hmc-slide-deck"},"headers":[],"relativePath":"reports/ai-as-an-interface/index.md","filePath":"reports/ai-as-an-interface/index.md"}'),n={name:"reports/ai-as-an-interface/index.md"};function o(r,e,l,c,d,u){return s(),t("div",null,[...e[0]||(e[0]=[i(`<section class="slide"><h1 id="ai-as-an-interface-layer-a-hows-my-commute-case-study" tabindex="-1">AI as an Interface Layer: A Hows My Commute Case Study <a class="header-anchor" href="#ai-as-an-interface-layer-a-hows-my-commute-case-study" aria-label="Permalink to &quot;AI as an Interface Layer: A Hows My Commute Case Study&quot;">​</a></h1><p><strong>Hows My Commute</strong></p><ul><li>Production integration case study, not a chatbot demo</li><li>Laravel backend with OpenAPI and OAuth2 (Passport) as the integration boundary</li><li>Reuse of existing domain logic and APIs; AI sits in front of them</li><li>Mixed audience: product, engineering, and leadership</li><li>Focus on reusable patterns for bringing AI safely into product systems</li><li>Suitable for sharing externally: clients, partners, and technical audiences</li></ul><details class="notes"><summary>Speaker Notes</summary> Frame this as an architecture and integration story. The value is in reusing what we already have—APIs, auth, domain logic—and letting AI act as an interface layer. Avoid positioning it as &quot;AI magic&quot;; emphasise contracts, security, and operational reality. </details></section><hr><section class="slide"><h1 id="product-context-what-is-hows-my-commute" tabindex="-1">Product Context: What Is Hows My Commute? <a class="header-anchor" href="#product-context-what-is-hows-my-commute" aria-label="Permalink to &quot;Product Context: What Is Hows My Commute?&quot;">​</a></h1><ul><li>Web-first product designed as a calm reassurance layer over daily travel</li><li>Advisory and decision-support, not an analytics-heavy or control-room experience</li><li>Existing API already powers the current UI (routes, times, status)</li><li>The AI layer reuses those same endpoints and services; users can ask in natural language (e.g. “How long to work?”) and receive an answer from their saved commute data</li><li>Surface extension, not rewrite: a conversational entry point is added without replacing backend logic</li></ul><details class="notes"><summary>Speaker Notes</summary> Explain that Hows My Commute is already a working product with a clear API. The AI integration is an additional way to access the same capabilities. This reduces risk and cost compared to building AI-specific backends. </details></section><hr><section class="slide"><h1 id="the-interface-shift" tabindex="-1">The Interface Shift <a class="header-anchor" href="#the-interface-shift" aria-label="Permalink to &quot;The Interface Shift&quot;">​</a></h1><ul><li>Shift from UI-driven flows to intent-driven interaction</li><li>Users ask outcome-first questions instead of navigating screens</li><li>Natural language becomes an entry point alongside buttons and forms</li><li>AI acts as an orchestration layer between the user and existing systems</li><li>AI changes the entry point, not the system logic; domain rules stay in the API</li></ul><details class="notes"><summary>Speaker Notes</summary> The behavioural shift is from &quot;click through these steps&quot; to &quot;ask what you need.&quot; The system still does the same work; the way the user reaches it changes. This is why contract-based integration matters—we are not reimplementing logic in the model. </details></section><hr><section class="slide"><h1 id="why-naive-ai-integrations-fail" tabindex="-1">Why Naive AI Integrations Fail <a class="header-anchor" href="#why-naive-ai-integrations-fail" aria-label="Permalink to &quot;Why Naive AI Integrations Fail&quot;">​</a></h1><ul><li>Secrets or credentials embedded in prompts or tool definitions</li><li>Unrestricted endpoints with no auth or scoping</li><li>No schemas: the model invents parameters and payloads</li><li>Hallucinated parameters lead to wrong or dangerous calls</li><li>No clear auth boundary between the user and backend</li><li>No audit trail or observability when things go wrong</li><li>Risks: data leakage, over-permission, untraceable failures, and compliance exposure</li></ul><details class="notes"><summary>Speaker Notes</summary> Many early AI integrations treat the backend as an open system. Production requires the opposite: strict contracts, user-scoped auth, and full observability. This slide sets up why we chose OpenAPI and OAuth2. </details></section><hr><section class="slide"><h1 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>AI Assistant Runtime</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Tool Selection Layer</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>OpenAPI Contract</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>OAuth (Laravel Passport)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>HMC API (Hows My Commute)</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Domain Logic</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Structured JSON</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Assistant Response</span></span></code></pre></div><ul><li>AI selects the tool and formats the response for the user</li><li>API authenticates and authorises; domain layer computes commute outcomes</li><li>AI does not compute commute times or hold business logic</li></ul><details class="notes"><summary>Speaker Notes</summary> Emphasise separation of responsibilities: the model chooses when to call which tool and how to explain the result. The API and domain layer own auth, authorisation, and all business rules. This keeps the system predictable and auditable. </details></section><hr><section class="slide"><h1 id="openapi-as-the-integration-contract" tabindex="-1">OpenAPI as the Integration Contract <a class="header-anchor" href="#openapi-as-the-integration-contract" aria-label="Permalink to &quot;OpenAPI as the Integration Contract&quot;">​</a></h1><ul><li>Typed parameters with required vs optional clearly defined</li><li>Enum constraints and validation rules in the schema</li><li>Predictable response schemas so the assistant can interpret results reliably</li><li>Version control of the contract as a product artefact</li><li>Governance boundary between AI and backend systems</li><li>Platform-agnostic reuse: same contract can drive GPT, Claude, or other runtimes</li></ul><details class="notes"><summary>Speaker Notes</summary> OpenAPI is not just documentation; it is the contract that prevents the model from inventing parameters or calling endpoints incorrectly. Treat it like an API product—maintained, versioned, and reviewed. </details></section><hr><section class="slide"><h1 id="oauth2-identity-model" tabindex="-1">OAuth2 &amp; Identity Model <a class="header-anchor" href="#oauth2-identity-model" aria-label="Permalink to &quot;OAuth2 &amp; Identity Model&quot;">​</a></h1><ul><li>Auth code flow: user authorises once; tokens are exchanged server-side</li><li>User-scoped tokens so every call is tied to an identity</li><li>Scopes and permissions limit what the assistant can do on the user’s behalf</li><li>Expiry and refresh keep tokens short-lived and revocable</li><li>Revocation and auditability support compliance and incident response</li><li>AI acts on behalf of a user, not as an admin; no credentials in prompts</li></ul><details class="notes"><summary>Speaker Notes</summary> The key message: the user’s identity and consent flow through OAuth. The assistant never sees passwords or long-lived secrets. When a token is revoked, the AI can no longer act for that user. This is the same security posture as the rest of the product. </details></section><hr><section class="slide"><h1 id="tool-invocation-mechanics-end-to-end" tabindex="-1">Tool Invocation Mechanics: End-to-End <a class="header-anchor" href="#tool-invocation-mechanics-end-to-end" aria-label="Permalink to &quot;Tool Invocation Mechanics: End-to-End&quot;">​</a></h1><ul><li>Flow: user query → tool decision → structured arguments from schema → API call with OAuth token → JSON response → formatted answer to user</li><li>Guardrails: schema validation before the call, explicit errors back to the assistant, no silent or hallucinated fallbacks</li><li>Determinism: domain data drives the answer first; language generation explains it second</li><li>Each tool call is a discrete, logged, and traceable step</li></ul><details class="notes"><summary>Speaker Notes</summary> Walk through one concrete example: &quot;How long to get to work?&quot; The assistant picks the commute tool, fills in parameters from the schema, calls the API with the user’s token, and then turns the JSON into a calm, readable response. No guessing; the source of truth is the API. </details></section><hr><section class="slide"><h1 id="operational-considerations" tabindex="-1">Operational Considerations <a class="header-anchor" href="#operational-considerations" aria-label="Permalink to &quot;Operational Considerations&quot;">​</a></h1><ul><li>Rate limiting on both the AI runtime and the API to avoid overload</li><li>Timeouts and retries with clear policies so users are not left hanging</li><li>Cost control: monitor LLM usage and API call volume</li><li>Structured errors so the assistant can surface helpful, calm messages instead of raw stack traces</li><li>Logging of tool calls, parameters, and outcomes for debugging and audit</li><li>Monitoring auth failures, latency, and error rates</li><li>Supportability and incident response: know which calls failed and why</li></ul><details class="notes"><summary>Speaker Notes</summary> Production AI integrations are operations-heavy. Teams need to treat tool calls like any other backend dependency: instrumented, limited, and recoverable. Calm UX depends on calm failure modes and clear observability. </details></section><hr><section class="slide"><h1 id="latency-ux-coupling" tabindex="-1">Latency &amp; UX Coupling <a class="header-anchor" href="#latency-ux-coupling" aria-label="Permalink to &quot;Latency &amp; UX Coupling&quot;">​</a></h1><ul><li>Latency comes from: LLM reasoning, tool selection, OAuth token use, and the API call itself</li><li>Conversational pacing: users expect a reply within a few seconds; long waits feel broken</li><li>Calm failure modes: reassuring messaging when the system is slow or unavailable</li><li>Backend reliability is user experience; if the API is slow or down, the assistant cannot hide it</li><li>Design for partial success and clear feedback rather than pretending latency does not exist</li></ul><details class="notes"><summary>Speaker Notes</summary> The product’s calm, reassuring tone must extend to errors and delays. &quot;Checking your commute…&quot; and &quot;Something’s taking longer than usual&quot; are better than silence or technical errors. Align product and engineering on these messages. </details></section><hr><section class="slide"><h1 id="lessons-learned" tabindex="-1">Lessons Learned <a class="header-anchor" href="#lessons-learned" aria-label="Permalink to &quot;Lessons Learned&quot;">​</a></h1><ul><li>Auth complexity outweighs prompt complexity; get identity and scoping right first</li><li>Loose schemas create unpredictable tool calls; strict OpenAPI pays off</li><li>Keep business logic out of the model; the API owns rules and computations</li><li>Observability is mandatory: log tool calls, outcomes, and failures</li><li>Treat OpenAPI as a product artefact: version it, review it, and govern changes</li><li>Reliability and calm UX go together; users need to trust that the system will respond predictably</li></ul><details class="notes"><summary>Speaker Notes</summary> These are engineering and product takeaways. The most common mistake is underinvesting in auth and schemas while overinvesting in prompt tuning. Emphasise that the pattern is reusable and that the same lessons apply to other AI–backend integrations. </details></section><hr><section class="slide"><h1 id="strategic-implications-reuse" tabindex="-1">Strategic Implications &amp; Reuse <a class="header-anchor" href="#strategic-implications-reuse" aria-label="Permalink to &quot;Strategic Implications &amp; Reuse&quot;">​</a></h1><ul><li>AI becomes an interface layer over existing APIs rather than a replacement for them</li><li>Faster feature layering: new entry points (voice, chat, assistants) can reuse the same backend</li><li>Reduced rebuild cost by extending surfaces instead of rewriting systems</li><li>Identify candidate systems that already expose structured, well-defined APIs</li><li>Reuse the pattern across products: editorial insights, analytics, support, reporting</li><li>Which existing systems already expose structured APIs that could become AI-accessible?</li></ul><details class="notes"><summary>Speaker Notes</summary> End with a call to reflection: where else could this pattern unlock value? Encourage the room to think about existing APIs, not greenfield AI projects. The goal is to make AI a standard way to access capabilities that already exist. </details></section>`,23)])])}const m=a(n,[["render",o]]);export{p as __pageData,m as default};
